    private SecuritySettings _security = new(false, DateTime.UtcNow.AddDays(-45), [
        new("sess-1", "Chrome on Windows", "New York, US", DateTime.UtcNow.AddMinutes(-5)),
        new("sess-2", "Firefox on macOS", "London, UK", DateTime.UtcNow.AddHours(-3)),
