@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private readonly List<string> _allChannels = MockSettingsService.AllChannels;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new List<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleChannel(string channel, ChangeEventArgs e)
    {
        var isEnabled = (bool)(e.Value ?? false);
        if (isEnabled)
        {
            _mutedChannels.Remove(channel);
        }
        else
        {
            if (!_mutedChannels.Contains(channel))
                _mutedChannels.Add(channel);
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, new List<string>(_mutedChannels));
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

