                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                    </div>
                </div>
            </div>
        </div>

        @* Active Sessions *@
        <div class="card mb-4">
            <div class="card-header">
                <strong>Active Sessions</strong>
            </div>
            <div class="card-body p-0">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_sessions is not null)
                        {
                            @foreach (var session in _sessions)
                            {
                                var isCurrent = session == _sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
