                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            <p class="text-muted small">Uncheck channels you want to mute</p>
            @foreach (var channel in _allChannels)
            {
                var isMuted = _mutedChannels.Contains(channel);
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox"
                           id="@($"ch-{channel}")"
                           checked="@(!isMuted)"
                           @onchange="e => ToggleChannel(channel, e)" />
                    <label class="form-check-label" for="@($"ch-{channel}")">
                        #@channel
                    </label>
                    @if (isMuted)
                    {
                        <span class="badge bg-secondary ms-2">Muted</span>
                    }
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Preferences")
        </button>

        @if (_showSuccess)
        {
            <div class="alert alert-success mt-3 fade show" role="alert">
                Notification preferences saved!
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private bool _showSuccess;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _mutedChannels = [];
    private readonly List<string> _allChannels = MockSettingsService.AllChannels;

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new List<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleChannel(string channel, ChangeEventArgs e)
    {
        var isEnabled = (bool)(e.Value ?? false);
        if (isEnabled)
        {
            _mutedChannels.Remove(channel);
        }
        else
        {
            if (!_mutedChannels.Contains(channel))
                _mutedChannels.Add(channel);
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _showSuccess = false;
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, new List<string>(_mutedChannels));
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
