{"file_text": "@using sv_da0dfd210d5e421089d7c02cb69a3caf.Models
@using sv_da0dfd210d5e421089d7c02cb69a3caf.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security</h3>
    <p class="text-muted">Manage your account security</p>
    <hr />

    @if (_loading)
    {
        <p>Loading security settings...</p>
    }
    else
    {
        @* Change Password Panel *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 style="cursor: pointer;" @onclick="() => _passwordExpanded = !_passwordExpanded">
                <strong>Change Password</strong>
                <span>@(_passwordExpanded ? "▲" : "▼")</span>
            </div>
            @if (_passwordExpanded)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="alert alert-danger">@_passwordError</div>
                    }
                    @if (_passwordSuccess)
                    {
                        <div class="alert alert-success">Password updated successfully!</div>
                    }
                    <button class="btn btn-warning" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @(_changingPassword ? "Updating..." : "Update Password")
                    </button>
                    @if (_settings?.LastPasswordChange is not null)
                    {
                        <small class="text-muted ms-3">
                            Last changed: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
                        </small>
                    }
                </div>
            }
        </div>

        @* Two-Factor Authentication *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <br />
                    <small class="text-muted">Add an extra layer of security to your account</small>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                    </div>
                </div>
            </div>
        </div>

        @* Active Sessions *@
        <div class="card mb-4">
            <div class="card-header">
                <strong>Active Sessions</strong>
            </div>
            <div class="card-body p-0">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_sessions is not null)
                        {
                            @foreach (var session in _sessions)
                            {
                                var isCurrent = session == _sessions.FirstOrDefault();
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-info ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>
        </div>

        @* Revoke Confirmation Dialog *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop fade show"></div>
            <div class="modal d-block fade show" tabindex="-1">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                            <p class="text-muted small">This will sign out that device immediately.</p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @(_revoking ? "Revoking..." : "Revoke Session")
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private SecuritySettings? _settings;
    private List<ActiveSession>? _sessions;
    private bool _twoFactorEnabled;

    // Password change state
    private bool _passwordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _passwordSuccess;
    private bool _changingPassword;

    // Session revoke state
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _sessions = new List<ActiveSession>(_settings.Sessions);
        _twoFactorEnabled = _settings.TwoFactorEnabled;
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword) || _newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New passwords do not match.";
            return;
        }

        _changingPassword = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _changingPassword = false;
        _passwordSuccess = true;
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _sessions?.Remove(_sessionToRevoke);
        _sessionToRevoke = null;
        _revoking = false;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}
