toolArgs.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 600px;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: 100%;
    padding: 0.6rem 1rem;
    border: none;
    background: none;
    text-align: left;
    border-radius: 0.375rem;
    color: #495057;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background-color: #f0f0f0;
}

.sidebar-item.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* Content area */
.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* Avatar */
.avatar-preview {
    padding: 1rem;
    background-color: #f8f9fa;
    border-radius: 0.5rem;
}

.avatar-preview img {
    border: 3px solid #dee2e6;
}

/* Modal backdrop layering */
.modal-backdrop {
    z-index: 1040;
}

.modal.d-block {
    z-index: 1050;
}

